// App.js
import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
  SafeAreaView,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics, { BiometryTypes } from 'react-native-biometrics';

const AUTH_KEY = '@authenticated';
const USER_CREDENTIALS_KEY = '@user_credentials';

const rnBiometrics = new ReactNativeBiometrics({
  allowDeviceCredentials: true,
});

// Login Screen Component
const LoginScreen = ({ onLoginSuccess, biometryType, onBiometricAuth }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handlePasswordLogin = async () => {
    if (!username.trim() || !password.trim()) {
      Alert.alert('Error', 'Please enter both username and password.');
      return;
    }

    setIsLoading(true);

    try {
      // Simulate API call for password authentication
      await new Promise((resolve) => setTimeout(resolve, 1000));

      // For demo purposes, accept any non-empty credentials
      // In production, validate against your backend
      if (username.trim() && password.trim()) {
        // Store credentials for future reference
        await AsyncStorage.setItem(
          USER_CREDENTIALS_KEY,
          JSON.stringify({ username: username.trim() })
        );
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onLoginSuccess(username.trim());
      } else {
        Alert.alert('Error', 'Invalid credentials. Please try again.');
      }
    } catch (error) {
      Alert.alert('Error', 'Login failed. Please try again.');
      console.error('Login error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const getBiometricLabel = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return 'Sign in with Face ID';
      case BiometryTypes.TouchID:
        return 'Sign in with Touch ID';
      case BiometryTypes.Biometrics:
        return 'Sign in with Fingerprint';
      default:
        return 'Sign in with Biometrics';
    }
  };

  const getBiometricIcon = () => {
    switch (biometryType) {
      case BiometryTypes.FaceID:
        return '👤';
      case BiometryTypes.TouchID:
      case BiometryTypes.Biometrics:
        return '👆';
      default:
        return '🔐';
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.loginContainer}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.subtitle}>Sign in to continue</Text>

        {biometryType && (
          <View style={styles.biometricSection}>
            <TouchableOpacity
              style={styles.biometricButton}
              onPress={onBiometricAuth}
              activeOpacity={0.7}
            >
              <Text style={styles.biometricIcon}>{getBiometricIcon()}</Text>
              <Text style={styles.biometricButtonText}>
                {getBiometricLabel()}
              </Text>
            </TouchableOpacity>

            <View style={styles.dividerContainer}>
              <View style={styles.divider} />
              <Text style={styles.dividerText}>OR</Text>
              <View style={styles.divider} />
            </View>
          </View>
        )}

        <View style={styles.formContainer}>
          <Text style={styles.inputLabel}>Username</Text>
          <TextInput
            style={styles.input}
            placeholder="Enter your username"
            placeholderTextColor="#999"
            value={username}
            onChangeText={setUsername}
            autoCapitalize="none"
            autoCorrect={false}
            editable={!isLoading}
          />

          <Text style={styles.inputLabel}>Password</Text>
          <TextInput
            style={styles.input}
            placeholder="Enter your password"
            placeholderTextColor="#999"
            value={password}
            onChangeText={setPassword}
            secureTextEntry
            autoCapitalize="none"
            autoCorrect={false}
            editable={!isLoading}
          />

          <TouchableOpacity
            style={[styles.loginButton, isLoading && styles.loginButtonDisabled]}
            onPress={handlePasswordLogin}
            disabled={isLoading}
            activeOpacity={0.7}
          >
            {isLoading ? (
              <ActivityIndicator color="#fff" />
            ) : (
              <Text style={styles.loginButtonText}>Sign In</Text>
            )}
          </TouchableOpacity>
        </View>

        {!biometryType && (
          <Text style={styles.noBiometricText}>
            Biometric authentication is not available on this device.
            {'\n'}Please use password to sign in.
          </Text>
        )}
      </View>
    </SafeAreaView>
  );
};

// Home Screen Component
const HomeScreen = ({ username, onLogout }) => {
  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.homeContainer}>
        <Text style={styles.welcomeEmoji}>🎉</Text>
        <Text style={styles.homeTitle}>Welcome Back!</Text>
        <Text style={styles.homeSubtitle}>
          {username ? `Signed in as ${username}` : 'You are authenticated'}
        </Text>

        <View style={styles.cardContainer}>
          <View style={styles.card}>
            <Text style={styles.cardTitle}>Authentication Status</Text>
            <View style={styles.statusRow}>
              <View style={styles.statusDot} />
              <Text style={styles.statusText}>Authenticated</Text>
            </View>
          </View>
        </View>

        <TouchableOpacity
          style={styles.logoutButton}
          onPress={onLogout}
          activeOpacity={0.7}
        >
          <Text style={styles.logoutButtonText}>Sign Out</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
};

// Main App Component
const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [biometryType, setBiometryType] = useState(null);
  const [username, setUsername] = useState('');

  useEffect(() => {
    initializeApp();
  }, []);

  const initializeApp = async () => {
    try {
      // Check biometric availability
      const { available, biometryType: type } =
        await rnBiometrics.isSensorAvailable();

      if (available) {
        setBiometryType(type);
      }

      // Check if user is already authenticated
      const authFlag = await AsyncStorage.getItem(AUTH_KEY);
      const storedCredentials = await AsyncStorage.getItem(USER_CREDENTIALS_KEY);

      if (authFlag === 'true' && storedCredentials) {
        const { username: storedUsername } = JSON.parse(storedCredentials);

        if (available) {
          // If biometrics available, require re-authentication
          const authenticated = await performBiometricAuth(true);
          if (authenticated) {
            setUsername(storedUsername);
            setIsAuthenticated(true);
          }
        } else {
          // If no biometrics, still require login
          // For better security, you might want to always require re-auth
          setUsername(storedUsername);
          setIsAuthenticated(true);
        }
      }
    } catch (error) {
      console.error('Initialization error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const performBiometricAuth = async (silent = false) => {
    try {
      const { available } = await rnBiometrics.isSensorAvailable();

      if (!available) {
        if (!silent) {
          Alert.alert(
            'Biometrics Unavailable',
            'Biometric authentication is not available on this device. Please use password login.'
          );
        }
        return false;
      }

      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: 'Confirm your identity',
        cancelButtonText: 'Cancel',
        fallbackPromptMessage: 'Use passcode',
      });

      if (success) {
        return true;
      } else {
        if (!silent) {
          Alert.alert(
            'Authentication Failed',
            'Biometric authentication was not successful. Please try again or use password login.'
          );
        }
        return false;
      }
    } catch (error) {
      console.error('Biometric auth error:', error);
      if (!silent) {
        Alert.alert(
          'Authentication Error',
          'An error occurred during biometric authentication. Please use password login.'
        );
      }
      return false;
    }
  };

  const handleBiometricLogin = async () => {
    const success = await performBiometricAuth();

    if (success) {
      try {
        // Check if we have stored credentials
        const storedCredentials = await AsyncStorage.getItem(
          USER_CREDENTIALS_KEY
        );

        let currentUsername = 'Biometric User';
        if (storedCredentials) {
          const parsed = JSON.parse(storedCredentials);
          currentUsername = parsed.username;
        } else {
          // First time biometric login - store default
          await AsyncStorage.setItem(
            USER_CREDENTIALS_KEY,
            JSON.stringify({ username: currentUsername })
          );
        }

        await AsyncStorage.setItem(AUTH_KEY, 'true');
        setUsername(currentUsername);
        setIsAuthenticated(true);
      } catch (error) {
        console.error('Error storing auth state:', error);
        Alert.alert('Error', 'Failed to complete authentication.');
      }
    }
  };

  const handlePasswordLoginSuccess = (loggedInUsername) => {
    setUsername(loggedInUsername);
    setIsAuthenticated(true);

    // Offer to enable biometrics if available
    if (biometryType) {
      const biometricName =
        biometryType === BiometryTypes.FaceID
          ? 'Face ID'
          : biometryType === BiometryTypes.TouchID
          ? 'Touch ID'
          : 'Fingerprint';

      Alert.alert(
        'Enable Biometric Login',
        `Would you like to enable ${biometricName} for faster sign-in next time?`,
        [
          {
            text: 'Not Now',
            style: 'cancel',
          },
          {
            text: 'Enable',
            onPress: async () => {
              const success = await performBiometricAuth();
              if (success) {
                Alert.alert(
                  'Success',
                  `${biometricName} has been enabled for future logins.`
                );
              }
            },
          },
        ]
      );
    }
  };

  const handleLogout = async () => {
    Alert.alert('Sign Out', 'Are you sure you want to sign out?', [
      {
        text: 'Cancel',
        style: 'cancel',
      },
      {
        text: 'Sign Out',
        style: 'destructive',
        onPress: async () => {
          try {
            await AsyncStorage.removeItem(AUTH_KEY);
            // Keep USER_CREDENTIALS_KEY so biometric login remembers the user
            setIsAuthenticated(false);
            setUsername('');
          } catch (error) {
            console.error('Logout error:', error);
            Alert.alert('Error', 'Failed to sign out. Please try again.');
          }
        },
      },
    ]);
  };

  if (isLoading) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color="#4A90D9" />
          <Text style={styles.loadingText}>Loading...</Text>
        </View>
      </SafeAreaView>
    );
  }

  if (isAuthenticated) {
    return <HomeScreen username={username} onLogout={handleLogout} />;
  }

  return (
    <LoginScreen
      onLoginSuccess={handlePasswordLoginSuccess}
      biometryType={biometryType}
      onBiometricAuth={handleBiometricLogin}
    />
  );
};

